<h5 class="mb-3">Equipos</h5>
<div class="card mb-3"><div class="card-body"><form method="post" action="/devices/create" class="row g-2"><?= csrf_field() ?><div class="col-md-3"><select required name="customer_id" class="form-select"><option value="">Cliente...</option><?php foreach($customers as $c): ?><option value="<?= e((string)$c['id']) ?>"><?= e($c['first_name'].' '.$c['last_name']) ?></option><?php endforeach; ?></select></div><div class="col-md-2"><select name="device_type" class="form-select"><option>computador</option><option>notebook</option><option>impresora</option><option>celular</option><option>tablet</option><option>otro</option></select></div><div class="col-md-2"><input name="brand" class="form-control" placeholder="Marca"></div><div class="col-md-2"><input name="model" class="form-control" placeholder="Modelo"></div><div class="col-md-2"><input name="serial_number" class="form-control" placeholder="Serie"></div><div class="col-md-1"><button class="btn btn-dark w-100">+</button></div></form></div></div>
<table class="table table-striped"><tr><th>ID</th><th>Cliente</th><th>Tipo</th><th>Marca/Modelo</th><th>Serie</th></tr><?php foreach($devices as $d): ?><tr><td><?= e((string)$d['id']) ?></td><td><?= e($d['customer']) ?></td><td><?= e($d['device_type']) ?></td><td><?= e($d['brand'].' '.$d['model']) ?></td><td><?= e((string)$d['serial_number']) ?></td></tr><?php endforeach; ?></table>
